'use server';

import { prisma } from "@/lib/db";
import { revalidatePath } from "next/cache";

export type VariantInput = {
    countryId: number;
    sku: string;
    barcode?: string;
    size?: number;
    sizeUnitId?: number;
    costPrice: number;
    basePrice: number;
    minStockLevel?: number;
};

export type ProductGroupState = {
    message?: string;
    errors?: Record<string, string[]>;
};

export async function createProductGroupWithVariants(
    prevState: ProductGroupState,
    data: {
        name: string;
        brandId: number;
        categoryId?: number;
        description?: string;
        baseUnitId: number; // Stock Unit (e.g. piece)
        variants: VariantInput[];
    }
): Promise<ProductGroupState> {
    const { name, brandId, categoryId, description, baseUnitId, variants } = data;

    if (!name || variants.length === 0) {
        return { message: "Name and at least one variant are required." };
    }

    try {
        await prisma.$transaction(async (tx) => {
            // 1. Create Group
            const group = await tx.productGroup.create({
                data: {
                    name,
                    brandId,
                    categoryId,
                    description
                }
            });

            // 2. Create Variants
            for (const v of variants) {
                await tx.product.create({
                    data: {
                        name: `${name}`, // Or append country? "Name (Country)" handled by UI logic or here? 
                        // Let's stick onto "Name" and let the UI/API distinguish by Country Relation.
                        // Actually, for searchability, keeping "Name (TR)" is useful, but data-wise redundant.
                        // I will assign the same name for now, or let separate logic handle display.
                        // User request: "head and shulders ... turkish"
                        productGroupId: group.id,
                        brandId,
                        categoryId,
                        unitId: baseUnitId, // Common stock unit
                        countryId: v.countryId,
                        sku: v.sku,
                        barcode: v.barcode,
                        size: v.size,
                        sizeUnitId: v.sizeUnitId,
                        costPrice: v.costPrice,
                        basePrice: v.basePrice,
                        minStockLevel: v.minStockLevel || 0,
                        isTaxIncluded: true // Default
                    }
                });
            }
        });

        revalidatePath('/admin/products');
        return { message: 'success' };
    } catch (e: any) {
        console.error(e);
        return { message: e.message || 'Failed to create product group.' };
    }
}
